import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"玩弄丙烯颜料-喷笔&马克笔","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/色彩管理/丙烯颜料.md","filePath":"ccc/色彩管理/丙烯颜料.md"}`),a={name:`ccc/色彩管理/丙烯颜料.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="玩弄丙烯颜料-喷笔-马克笔" tabindex="-1">玩弄丙烯颜料-喷笔&amp;马克笔 <a class="header-anchor" href="#玩弄丙烯颜料-喷笔-马克笔" aria-label="Permalink to “玩弄丙烯颜料-喷笔&amp;马克笔”">​</a></h1><p>据我测试某国产品牌丙烯马克笔，不知道怎么回事耐候性很差，在阳台上晒了两个月后，一眼明显褪色。</p><p>后续将测试盾牌、collide丙烯马克笔墨水耐候性。</p><p>高登Golden丙烯颜料主打所谓”艺术家级“，还有现成的产品-高流质丙烯颜料，可用于喷笔。其官网列出了产品所用的色料CI号，可以判断是否是混合出的颜色，进而自己调色。</p><p>不排除其他颜料实力也同样不俗，但本文将更侧重高登高流质丙烯颜料。</p><p>据我测试，DIY的话丙烯马克笔不太好用，将更侧重于喷笔使用。</p><blockquote><p>国产丙烯颜料的根本问题不是技术问题，而是市场问题，是自己不把自己当回事的问题。</p></blockquote><blockquote><p>某国产品牌言之凿凿，已成立色彩实验室，既不建立颜色库，用的色标号也是不知道谁一拍脑袋想出来的标准，有现成的标准不用，自嗨的神秘标准也不建立wiki，让人摸不着头脑。</p></blockquote><h2 id="高登高流质不适合丙烯马克笔" tabindex="-1">高登高流质不适合丙烯马克笔 <a class="header-anchor" href="#高登高流质不适合丙烯马克笔" aria-label="Permalink to “高登高流质不适合丙烯马克笔”">​</a></h2><p>目前在售空笔主要有三种，直液式、前按压阀门式、后按压阀门式。</p><p><strong>DIY只考虑阀门式。</strong>直液式基本可以视为一次性，装上去以后几乎拔不出来，除非笔杆打洞。</p><p>直液式丙烯马克笔装满笔身约3ml，每次加墨感觉2.5ml差不多。 前按压阀门式装满笔身约5.5ml，每次加墨感觉5ml差不多。</p><p>阀门式笔头约吸0.18ml、吸墨海绵约吸0.2ml 直液式 笔头约吸0.15ml、吸墨棒约吸0.1ml。</p><p>阀门式按压出墨，有一圈吸墨海绵，笔头的另一端泡在海绵里。 直液式是一根不知材质的细棒子吸墨，传递给笔头。外面套个黑壳营销成高大上的阻尼阀。</p><p><strong>高登高流质+直液式供墨速度太慢</strong>，用缓干剂稀释后还是供不上。</p><p>混色静置一晚会分层，尽管阀门式供墨前可以先摇匀，但在吸墨海绵里也会分层，导致颜色会变，所以高登高流质丙烯颜料混色不具有实用性，只能买现成的，后续将测试补充分散剂并使用磁力搅拌器搅拌看是否解决分层。</p><blockquote><p>硬笔头、棉棒吸墨的用不了丙烯马克笔墨水，靠棉棒吸墨的话，吸墨过程就会成膜干掉，要提前润湿，往往导致太稀，笔头会淌墨，真的用吧，又供不上墨。</p></blockquote><p>吸墨海绵和笔头酌情用缓干剂提前润湿，防止丙烯酸树脂在润湿过程中成膜。</p><p>阀门式笔头和吸墨海绵干了的话就要换了，一般会送笔头，但不送吸墨海绵，多久会干可能要看环境湿度，测试中。</p><p>长期闲置，考虑笔盖里直接加点“DIY维护剂”或缓干剂，下次使用前倒掉，用纸巾吸一吸，重新上墨后盖着笔盖静置数小时即可重新启用。</p><h3 id="稀释高登厚重型颜料" tabindex="-1">稀释高登厚重型颜料 <a class="header-anchor" href="#稀释高登厚重型颜料" aria-label="Permalink to “稀释高登厚重型颜料”">​</a></h3><p>不同型颜料的单价差不多，如果用厚重型颜料稀释成高流质颜料，成本会低很多。</p><p>喷枪媒介/高流质媒介的单价约0.56￥/ml（118ml），0.37￥/ml（473ml），0.176￥/ml（3780ml）。理论添加量约1/2。</p><p>厚重型颜料单价约1块多/ml，理论添加量约1/8，3/8的纯净水。</p><p>据<a href="https://goldenartistcolors.com/resources/airbrush-tips-vol2" target="_blank" rel="noreferrer">高登介绍</a>，高流质媒介就是没加色料的“高流质丙烯颜料”，含同款成膜树脂。而喷枪媒介的设计树脂含量是流质颜料稀释比例正好1:1。高流质媒介的标称光泽度、透明度比喷枪媒介高。</p><p>高登推荐喷枪媒介+流质丙烯颜料1:1比例混合。厚重型，水，喷枪媒介1:3:4。</p><p>综合来看，厚重型丙烯颜料配合<code>喷枪媒介</code>或<code>高流质媒介</code>稀释后用于丙烯马克笔具有理论可行性。</p><p>高登色彩库数据显示，<strong>高流质光泽度为0</strong>，而厚重和流质都有光泽度。</p><h3 id="高登助剂" tabindex="-1">高登助剂 <a class="header-anchor" href="#高登助剂" aria-label="Permalink to “高登助剂”">​</a></h3><p>根据高登的SDS安全信息披露，主要使用保湿剂-丙二醇，ph调节剂辅助树脂溶解-氨水。</p><p>高登高流质丙烯颜料的商品介绍，添加了”酸性物质“防笔头干，推测氨可能在笔头挥发，添加酸性物质可能固铵。 不清楚为什么不用类似于AMP-95这样不挥发的ph调节剂，高登稀释剂根据SDS披露用了二甲基乙醇胺。</p><p>Retarder 缓凝剂 粘度2100 - 2700 cP，延长干燥时间，减少调色盘上结皮。 商品介绍中提到主要含有丙二醇起到保湿作用。通常15%的添加量较为安全。 可能补充了成膜树脂。</p><p>OPEN Thinner 稀释剂 粘度300 - 500 cP，稀释粘稠度但不延长干燥时间。 SDS提到用了0.1%~1%的cas108-01-0</p><p>稀释剂会减少单位面积内的颜料，涂布会变薄，加的越多颜色越淡，通常含成膜树脂。</p><p>Wetting Aid 润湿剂 粘度&lt;200cP，降低表面张力，增加光滑度和流动性，改善在多孔表面的表现。 SDS提到用了20%~30%的cas9036-19-5，曲拉通X-114，含APEO，有毒不环保。</p><p>友商通常称为Flow Improver流动改进剂，防止涂布过程中凝结成液滴，通常不含成膜树脂，主要成分就是润湿剂。</p><p>Airbrush Medium 喷枪媒介（含缓凝剂、流平剂、流动改善剂retarders, leveling agents, and flow improvers） High Flow Medium 高流质媒介（改善透明度和成膜硬度increased transparency and film hardness）</p><p>据<a href="https://goldenartistcolors.com/resources/airbrush-tips-vol2" target="_blank" rel="noreferrer">高登介绍</a>，高流质媒介就是没加色料的“高流质丙烯颜料”，而喷枪媒介的设计是流质颜料稀释比例1:1。 高流质媒介的标称光泽度、透明度要比喷枪媒介高。</p><p>友商surfactant界面活性剂，改善颜料颗粒在涂布后的调节能力，干燥前可以移动微调。</p><h3 id="diy助剂" tabindex="-1">DIY助剂 <a class="header-anchor" href="#diy助剂" aria-label="Permalink to “DIY助剂”">​</a></h3><p>高登官方信息通常会用氨水作为ph调节剂或溶剂，但氨水具有挥发性与刺激性，味很足。</p><p>高登SDS显示，其润湿剂的主要成分为曲拉通X-114，然而含APEO，有毒不环保。</p><h4 id="diy维护剂" tabindex="-1">DIY维护剂 <a class="header-anchor" href="#diy维护剂" aria-label="Permalink to “DIY维护剂”">​</a></h4><p>保湿剂-丙二醇5%； 非离子润湿剂 赢创Surfynol465 1% ph调节剂-AMP95-0.35% 防腐剂-1,2-苯并异噻唑啉-3-酮 0.02%</p><p>实际操作可行，暂时没发现异常。</p><h4 id="diy清洗剂" tabindex="-1">DIY清洗剂 <a class="header-anchor" href="#diy清洗剂" aria-label="Permalink to “DIY清洗剂”">​</a></h4><p>保湿剂-丙二醇12%； 清洗剂-异丙醇8%； 非离子润湿剂-赢创Surfynol465 2% ph调节剂-AMP95-0.35% 防腐剂-1,2-苯并异噻唑啉-3-酮 0.02%</p><p><strong>清洗后必须再用纯净水清洗。</strong>喷完立刻清洗用DIY维护剂即可，异丙醇主要针对已半成膜形成软膜。</p><p>如果密封圈是氟胶圈或特氟龙PTFE，考虑丙二醇10%+异丙醇15%。如果是三元乙丙EPDM胶圈，考虑丙二醇12%+异丙醇8%，喷完就清洗，可以再稀释50%。</p><p>清洗剂中的醇类物质对密封胶圈具有溶胀作用，不能长时间浸泡。该配方相对还算温和，只适用于日常清洗，不能用于已形成硬膜的场景。已形成硬膜的场景，考虑金属件拆出来浸泡清洗液，无果考虑购置丙烯颜料去除剂，短时浸泡。</p><h4 id="diy-媒介剂-稀释剂" tabindex="-1">DIY”媒介剂“/”稀释剂“ <a class="header-anchor" href="#diy-媒介剂-稀释剂" aria-label="Permalink to “DIY”媒介剂“/”稀释剂“”">​</a></h4><p>保湿剂-丙二醇5%； 非离子润湿剂 赢创Surfynol465 2% 流平剂BYK-333 0.8% ph调节剂-AMP95-0.35% 防腐剂-1,2-苯并异噻唑啉-3-酮 0.02% 丙烯酸成膜树脂乳液 50%</p><p>补充分散剂3%</p><p>也许高登用的就是市面上普通的丙烯酸树脂乳液，但也有可能是定制开发的树脂乳液。 稳妥起见，可能还是优选高登原装添加剂。</p><p>不加成膜树脂，替代纯水来稀释厚重型丙烯颜料后配合喷枪媒介或高流质媒介的效果可能相对更好。</p><p><strong>系我YY，没有实际测试过可行</strong>。</p><h4 id="diy-消光" tabindex="-1">DIY”消光“ <a class="header-anchor" href="#diy-消光" aria-label="Permalink to “DIY”消光“”">​</a></h4><p>可能可以添加于高流质颜料、高登媒介剂、DIY”媒介剂“。 消光粉-赢创 ACEMATT 3300 4.5% 分散剂-BYK-190 1.5% ph调节剂-AMP95-0.35%，需要搅拌，原体系中氨挥发不知是否有影响，可能考虑补充ph调节剂。</p><p><strong>系我YY，没有实际测试过可行</strong>。</p><h2 id="高登丙烯颜料" tabindex="-1">高登丙烯颜料 <a class="header-anchor" href="#高登丙烯颜料" aria-label="Permalink to “高登丙烯颜料”">​</a></h2><p>通常钛白粉粘度在体系中相对较高，作为参考，甘油粘度约1500cP，水粘度约1cP，沐浴露粘度约1000~5000cP。</p><ul><li><p>High Flow Acrylics 高流质丙烯颜料<a href="https://goldenartistcolors.com/products/golden-artist-acrylics/heavy-body/pigment-data" target="_blank" rel="noreferrer">色库</a>，整体粘度约60 - 300 cP。</p></li><li><p>Fluid Acrylics 流质型丙烯颜料 <a href="https://goldenartistcolors.com/products/golden-artist-acrylics/fluid/pigment-data" target="_blank" rel="noreferrer">色库</a></p></li></ul><p>钛白-900~1000cP，其他颜色基本在400~1000cP左右。整体200~1600cP。</p><ul><li>Heavy Body Acrylics 厚重型丙烯颜料 <a href="https://goldenartistcolors.com/products/golden-artist-acrylics/heavy-body/pigment-data" target="_blank" rel="noreferrer">色库</a></li></ul><p>钛白22000~24000cP，深色约22000~28000，浅色约5000~6000cP。</p><ul><li>OPEN Slow-Drying Acrylics 慢干型 <a href="https://goldenartistcolors.com/products/golden-artist-acrylics/open/pigment-data" target="_blank" rel="noreferrer">色库</a></li><li>SoFlat Matte Acrylics 哑光丙烯颜料<a href="https://goldenartistcolors.com/products/golden-artist-acrylics/soflat/pigment-data" target="_blank" rel="noreferrer">色库</a>，整体粘度约1500~2300cP。</li></ul>`,66)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};